var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"단단히 미쳤어.","JPN":"狂ってる。","ENG":"You're completely insane.","TWN":"真是瘋了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"왜 이제 와서 이 일에 열을 내는 거지?","JPN":"なぜ今更この件にこだわる？","ENG":"Why are you so worked up now?","TWN":"為什麼現在才對這件事這麼費勁？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"참견해봤자 자네에게 전혀 득이 없는 일인데.","JPN":"首を突っ込んだところで、君に得はないはずだ。","ENG":"Getting involved doesn't benefit you in any way.","TWN":"插手這件事對你一點好處都沒有。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알 필요 없잖아!","JPN":"あなたには関係ない！","ENG":"Like I need a reason!","TWN":"你不需要知道！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽……! 그 모습은?","JPN":"っ……！　その姿は？","ENG":"Ugh...! Your arm...!","TWN":"呃……！那是？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"침식 증후군이라는 거짓말을 해서 미안하군.","JPN":"侵食症候群なんて嘘をついてすまなかったな。","ENG":"Apologies for the deception. I never had Corruption Syndrome.","TWN":"對不起，我撒謊說這是侵蝕症候群。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나도 <color=#ffd34c>붉은 달 현상</color>의 감염자였네.","JPN":"私も<color=#ffd34c>赤い月現象</color>の感染者でね。","ENG":"I was afflicted by the <color=#ffd34c>Red Moon phenomenon</color>.","TWN":"其實我也是<color=#ffd34c>紅月現象</color>的感染者啊。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네와는 다르게, 반쪽짜리지만 말일세.","JPN":"まあ、君とは違って半端者だけど。","ENG":"Unlike you, though, I'm only half-afflicted.","TWN":"我和你不一樣，我只是個半吊子。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"何だって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는 내 몸을 갉아먹는 광증을 이겨내기 위해 연구를 시작했네.","JPN":"私はこの体を蝕む狂症を乗り越えるために研究を始めた。","ENG":"I started my research to overcome the madness eating away at me.","TWN":"我開始研究如何戰勝吞噬我身體的狂症。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"처음엔 가문의 식솔들을 사용했지.","JPN":"最初は家の者たちを使ったよ。","ENG":"At first, I used my own household servants.","TWN":"一開始我用了家裡的僕人。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 인자를 주사하기 가장 손쉬운 자들이었으니.","JPN":"私のファクターを注入する実験体としては、うってつけだったからね。","ENG":"They were the most convenient test subjects.","TWN":"他們是最容易注入我基因的人。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 묘지에서 본 시체는……?","JPN":"じゃあ、墓地で見た死体は……？","ENG":"Then the corpse in the graveyard was...","TWN":"那麼在墓地看到的屍體是……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"가장 마지막까지 남은 사용인이지.","JPN":"最後まで生き残っていた使用人さ。","ENG":"My last remaining servant.","TWN":"是最後留下來的實驗品。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"도망치려다 침식체에게 죽은 건 아쉬운 일이었지만.","JPN":"逃げようとして侵食体に殺されてしまったのはとても残念だった。","ENG":"One tried to escape but was devoured by a C.O. A shame, really.","TWN":"在逃跑時被侵蝕體殺死了，真是可惜。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"실험은 순조롭지 못했어.","JPN":"実験は順調ではなかった。","ENG":"The experiments didn't go well.","TWN":"實驗不太順利。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"변이는 성공했으나 광증이 발현하기 일쑤였지.","JPN":"変異には成功したものの、狂症が発現しがちだった。","ENG":"While I succeeded in inducing mutations, the madness was uncontrollable.","TWN":"變異雖然成功了，但狂症時常出現。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네에게 억지로 광증을 일으킨 것과 다르게 말일세.","JPN":"君に無理矢理狂症を起こしたのとは違ってね。","ENG":"Unlike what I forced onto you.","TWN":"和強行讓你發狂不同。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"수많은 실패 끝에, 나는 깨닫고 말았어.","JPN":"数多の失敗の末に、私は気づいてしまったのだよ。","ENG":"After countless failures, I came to a realization.","TWN":"經歷了無數次失敗後，我終於明白了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 반쪽짜리 인자로는 절대 연구를 완성할 수 없다는 것을.","JPN":"私のこの中途半端なファクターでは、決して研究を完成できないということに。","ENG":"That my half-factor would never be enough to complete my research.","TWN":"憑我那半吊子的資質，絕對無法完成研究。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신 식솔들을 실험에 이용했다고?","JPN":"自分の家の者たちを実験に利用しただって……？","ENG":"You experimented on your own people?!","TWN":"你竟然把你的家人用於實驗？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"혁신을 위한 희생이지.","JPN":"革新を遂げるための犠牲さ。","ENG":"A necessary sacrifice for progress.","TWN":"為了革新而犧牲。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};